    18→
    19→	load<T extends SomeEntity>(typeRef: TypeRef<T>, id: PropertyType<T, "_id">, query?: Dict, extraHeaders?: Dict, ownerKey?: Aes128Key): Promise<T> {
    20→		return this._target.load(typeRef, id, query, extraHeaders, ownerKey)
    21→	}
    22→
    23→	async loadAll<T extends ListElementEntity>(typeRef: TypeRef<T>, listId: Id, start?: Id): Promise<T[]> {
    24→		const typeModel = await resolveTypeReference(typeRef)
    25→
    26→		if (!start) {
    27→			start = typeModel.values["_id"].type === ValueType.GeneratedId ? GENERATED_MIN_ID : CUSTOM_MIN_ID
    28→		}
    29→
    30→		const elements = await this.loadRange<T>(typeRef, listId, start, RANGE_ITEM_LIMIT, false)
    31→		if (elements.length === RANGE_ITEM_LIMIT) {
    32→			let lastElementId = getLetId(elements[elements.length - 1])[1]
    33→			const nextElements = await this.loadAll<T>(typeRef, listId, lastElementId)
    34→			return elements.concat(nextElements)
    35→		} else {
    36→			return elements
    37→		}
    38→	}
    39→
    40→	async loadReverseRangeBetween<T extends ListElementEntity>(
    41→		typeRef: TypeRef<T>,
    42→		listId: Id,
    43→		start: Id,
    44→		end: Id,
    45→		rangeItemLimit: number = RANGE_ITEM_LIMIT,
    46→	): Promise<{
    47→		elements: T[]
    48→		loadedCompletely: boolean
    49→	}> {
    50→		const typeModel = await resolveTypeReference(typeRef)
    51→		if (typeModel.type !== Type.ListElement) throw new Error("only ListElement types are permitted")
    52→		const loadedEntities = await this._target.loadRange<T>(typeRef, listId, start, rangeItemLimit, true)
    53→		const filteredEntities = loadedEntities.filter((entity) => firstBiggerThanSecond(getElementId(entity), end, typeModel))
    54→
    55→		if (filteredEntities.length === rangeItemLimit) {
    56→			const lastElementId = getElementId(filteredEntities[loadedEntities.length - 1])
    57→			const { elements: remainingEntities, loadedCompletely } = await this.loadReverseRangeBetween<T>(typeRef, listId, lastElementId, end, rangeItemLimit)
    58→			return {
    59→				elements: filteredEntities.concat(remainingEntities),
    60→				loadedCompletely,
    61→			}
    62→		} else {
    63→			return {
    64→				elements: filteredEntities,
    65→				loadedCompletely: wasReverseRangeCompletelyLoaded(rangeItemLimit, loadedEntities, filteredEntities),
    66→			}
    67→		}
    68→	}
