    76→	 */
    77→	loadMultiple<T extends SomeEntity>(typeRef: TypeRef<T>, listId: Id | null, elementIds: Id[]): Promise<T[]> {
    78→		return this._target.loadMultiple(typeRef, listId, elementIds)
    79→	}
