   105→function wasReverseRangeCompletelyLoaded<T extends ListElementEntity>(rangeItemLimit: number, loadedEntities: Array<T>, filteredEntities: Array<T>): boolean {
   106→	if (loadedEntities.length < rangeItemLimit) {
   107→		const lastLoaded = last(loadedEntities)
