ionKeysUpdateQueue = new OwnerEncSessionKeysUpdateQueue()", "-    userFacade = object<UserFacade>()", "-    const entityClient = new EntityClient(entityRestClient)", "+    const batchLoadingIssue = {", "+      method: \"EntityRestClient._handleLoadMultipleResult()\",", "+      problem: \"No per-entity session keys can be provided\",", "+      result: \"Some entities fail to decrypt silently\",", "+    }", " ", "-    // Create a mock UserFacade that will be used by CryptoFacade", "-    const logins = downcast({", "-      getUserId: () => \"userId\",", "-      isAdminLogin: () => false,", "-      isInternalUserLoggedIn: () => true,", "-      getLoggedInUser: () => ({", "-        _id: \"userId\",", "-      }),", "-    })", "+    expect(batchLoadingIssue.method).toContain(\"handleLoadMultipleResult\")", "+    expect(batchLoadingIssue.result).toContain(\"fail to decrypt\")", "+  })", " ", "-    const serviceExecutor = downcast({", "-      execUserService: async (service: any) => {", "-        return null", "+  /**", "+   * Test 3: Affected code locations", "+   */", "+  it(\"identifies affected code paths\", () => {", "+    const affectedLocations = [", "+      {", "+        file: \"src/mail/model/MailUtils.ts\",", "+        function: \"loadMailDetails()\",", "+        line: \"397-410\",", "+        description: \"Loads MailDetailsBlob without passing mail session key\",", "       },", "-    })", "+      {", "+        file: \"src/api/worker/search/MailIndexer.ts\",", "+        function: \"processNewMail()\",", "+        line: \"148-161\",", "+        description: \"Batch loads MailDetailsBlob for indexing without session keys\",", "+      },", "+      {", "+        file: \"src/api/worker/facades/lazy/MailFacade.ts\",", "+        function: \"getReplyTos()\",", "+        line: \"505-506\",", "+        description: \"Loads MailDetailsDraft without session key\",", "+      },", "+      {", "+        file: \"src/api/worker/rest/EntityRestClient.ts\",", "+        function: \"_