the fix\", () => {", "+    const expectedFix = {", "+      approach1: \"Cache parent session key before loading child entities\",", "+      approach2: \"Pass ownerKey to loadMultiple() for batch loading\",", "+      approach3: \"Add session key map parameter to loadMultiple()\",", "+      approach4: \"Automatically propagate session keys from parent to child in CryptoFacade\",", "+    }", " ", "-      // Try to decrypt the MailDetailsBlob without providing the owner key", "-      // This simulates the scenario where the session key from Mail is not available", "-      const mailDetailsBlobModel = await resolveTypeReference(MailDetailsBlobTypeRef)", "+    const fixMustAchieve = [", "+      \"Non-legacy mails can load MailDetailsBlob successfully\",", "+      \"Non-legacy mail bodies decrypt and display content\",", "+      \"Reply-to addresses load from MailDetailsDraft\",", "+      \"Mail search indexing works for non-legacy mails\",", "+      \"No missing key errors in console\",", "+    ]", " ", "-      // Create a raw encrypted MailDetailsBlob (as it would come from the server)", "-      const encryptedMailDetailsBlobData = {", "-        _id: [mailDetailsBlobArchiveId, mailDetailsBlobElementId],", "-        _owner: userId,", "-        _ownerGroup: groupId,", "-        _ownerEncSessionKey: uint8ArrayToBase64(encryptedMailDetailsBlobSessionKey),", "-        details: {", "-          _id: \"detailsId\",", "-          body: {", "-            _id: \"bodyId\",", "-            _owner: userId,", "-            _ownerGroup: groupId,", "-            _ownerEncSessionKey: uint8ArrayToBase64(", "-              bitArrayToUint8Array(", "-                encryptKey(privateKey, bitArrayToUint8Array(bodySessionKey)),", "-              ),", "-            ),", "-            text: encryptedBodyText,", "-            compressedText: null,", "-          },", "-          headers: null,", "-          recipients: {},", "-          replyTos: [],", "-          authStatus: \"0\",", "-          